#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k03176Custom {
public:
    __aicore__ inline KernelCa6k03176Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR values, GM_ADDR indices,
                                uint32_t totalLength, uint32_t columns, uint32_t rowSize,
                                uint32_t tileLength, int32_t dim)
    {
        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLength);
        valuesGm_.SetGlobalBuffer((__gm__ float*)values, columns);
        indicesGm_.SetGlobalBuffer((__gm__ int64_t*)indices, columns);
        columns_ = columns;
        rowSize_ = rowSize;
        tileLen_ = tileLength;

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        // temporary buffers for mask and reduction
        pipe_.InitBuffer(maskBuf_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpBuf_, 1, tileLen_ * sizeof(float));
        // small buffer for single-element reads
        pipe_.InitBuffer(singleBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (columns_ == 0 || rowSize_ == 0) return;
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        if (blockIdx >= columns_) return;

        uint32_t colStart = blockIdx * rowSize_;

        // First pass: count non-NaN elements in this column
        uint32_t nonNanCount = 0;
        for (uint32_t offset = 0; offset < rowSize_; offset += tileLen_) {
            uint32_t curLen = (offset + tileLen_ > rowSize_) ? rowSize_ - offset : tileLen_;
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[colStart + offset], curLen);
            inQueueX_.EnQue(xLocal);
            AscendC::LocalTensor<float> xDeque = inQueueX_.DeQue<float>();

            AscendC::LocalTensor<float> nanMask = maskBuf_.AllocTensor<float>();
            AscendC::IsNan(nanMask, xDeque, curLen);
            // sum mask: nanMask is 1.0 for NaN
            AscendC::LocalTensor<float> sumTmp = tmpBuf_.AllocTensor<float>();
            AscendC::ReduceAdd(sumTmp, nanMask, curLen);
            float nanCount = sumTmp.GetValue(0);
            nonNanCount += (curLen - static_cast<uint32_t>(nanCount));

            tmpBuf_.FreeTensor(sumTmp);
            maskBuf_.FreeTensor(nanMask);
            inQueueX_.FreeTensor(xDeque);
        }

        if (nonNanCount == 0) {
            valuesGm_.SetValue(blockIdx, 0.0f);
            indicesGm_.SetValue(blockIdx, 0);
            return;
        }

        uint32_t k = (nonNanCount - 1) / 2;

        // Quickselect using counting with vectorized operations
        int64_t lowIndex = 0;
        int64_t highIndex = static_cast<int64_t>(rowSize_) - 1;
        float medianVal = 0.0f;
        int64_t medianIdx = 0;
        uint32_t maxIter = 200;

        while (lowIndex <= highIndex && maxIter > 0) {
            --maxIter;

            // Pick pivot: median-of-three from low, mid, high (skip NaN)
            int64_t mid = lowIndex + (highIndex - lowIndex) / 2;
            float vLow = ReadOneFloat(colStart, lowIndex);
            float vMid = ReadOneFloat(colStart, mid);
            float vHigh = ReadOneFloat(colStart, highIndex);

            // Find a non-NaN pivot value
            float pivotVal;
            int64_t pivotPos;
            if (!(vLow != vLow)) { // vLow is not NaN
                pivotVal = vLow; pivotPos = lowIndex;
            } else if (!(vMid != vMid)) {
                pivotVal = vMid; pivotPos = mid;
            } else if (!(vHigh != vHigh)) {
                pivotVal = vHigh; pivotPos = highIndex;
            } else {
                // All three are NaN, scan for any non-NaN in [lowIndex, highIndex]
                bool found = false;
                for (int64_t pos = lowIndex; pos <= highIndex; ++pos) {
                    float v = ReadOneFloat(colStart, pos);
                    if (!(v != v)) { // not NaN
                        pivotVal = v;
                        pivotPos = pos;
                        found = true;
                        break;
                    }
                }
                if (!found) {
                    // All remaining elements are NaN -> should not happen since nonNanCount>0
                    break;
                }
            }

            // Count elements less than and equal to pivot (ignoring NaN)
            uint32_t lessCount = 0;
            uint32_t eqCount = 0;
            int64_t eqPos = -1;

            for (uint32_t offset = 0; offset < rowSize_; offset += tileLen_) {
                uint32_t curLen = (offset + tileLen_ > rowSize_) ? rowSize_ - offset : tileLen_;
                if (curLen == 0) break;

                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[colStart + offset], curLen);
                inQueueX_.EnQue(xLocal);
                AscendC::LocalTensor<float> xDeque = inQueueX_.DeQue<float>();

                // Mask for valid (not NaN)
                AscendC::LocalTensor<float> validMask = maskBuf_.AllocTensor<float>();
                AscendC::IsNan(validMask, xDeque, curLen);
                // validMask now 1.0 for NaN; invert: v = 1 - nan
                AscendC::LocalTensor<float> tmp1 = tmpBuf_.AllocTensor<float>();
                AscendC::Muls(tmp1, validMask, -1.0f, curLen);
                AscendC::Adds(tmp1, tmp1, 1.0f, curLen);
                // tmp1 now 1 for valid, 0 for NaN
                AscendC::LocalTensor<float> lessMask = tmpBuf_.AllocTensor<float>(); // reuse
                AscendC::Compare(lessMask, xDeque, pivotVal, AscendC::CMPMODE::LT, curLen);
                AscendC::Mul(lessMask, lessMask, tmp1, curLen); // lessMask only for valid
                AscendC::ReduceAdd(tmp1, lessMask, curLen);
                lessCount += static_cast<uint32_t>(tmp1.GetValue(0));

                AscendC::LocalTensor<float> eqMask = tmpBuf_.AllocTensor<float>();
                AscendC::Compare(eqMask, xDeque, pivotVal, AscendC::CMPMODE::EQ, curLen);
                AscendC::Mul(eqMask, eqMask, tmp1, curLen);
                AscendC::ReduceAdd(tmp1, eqMask, curLen);
                float eqAdd = tmp1.GetValue(0);
                eqCount += static_cast<uint32_t>(eqAdd);

                // record last equal position in this tile
                if (eqAdd > 0.0f) {
                    // find first equal position within this tile (for performance, we just take the last possible)
                    // We'll update eqPos only if needed; precise position not required for correctness, as long as we output some index of a non-NaN equal to median.
                    for (uint32_t i = 0; i < curLen; ++i) {
                        int64_t absPos = static_cast<int64_t>(offset + i);
                        if (absPos >= lowIndex && absPos <= highIndex) {
                            float v = xDeque.GetValue(i);
                            if (!(v != v) && v == pivotVal) {
                                eqPos = absPos;
                            }
                        }
                    }
                }

                inQueueX_.FreeTensor(xDeque);
                maskBuf_.FreeTensor(validMask);
            }

            if (k < lessCount) {
                highIndex = pivotPos - 1;
            } else if (k < lessCount + eqCount) {
                medianVal = pivotVal;
                medianIdx = eqPos;
                break;
            } else {
                k -= (lessCount + eqCount);
                lowIndex = pivotPos + 1;
            }
        }

        valuesGm_.SetValue(blockIdx, medianVal);
        indicesGm_.SetValue(blockIdx, medianIdx);
    }

private:
    __aicore__ inline float ReadOneFloat(uint32_t colStart, int64_t pos)
    {
        uint32_t gmOffset = colStart + static_cast<uint32_t>(pos);
        AscendC::LocalTensor<float> tmp = singleBuf_.AllocTensor<float>();
        AscendC::DataCopy(tmp, xGm_[gmOffset], 1);
        float val = tmp.GetValue(0);
        singleBuf_.FreeTensor(tmp);
        return val;
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> maskBuf_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpBuf_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> singleBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> valuesGm_;
    AscendC::GlobalTensor<int64_t> indicesGm_;

    uint32_t columns_;
    uint32_t rowSize_;
    uint32_t tileLen_;
};

extern "C" __global__ __aicore__ void ca6k03176_custom(GM_ADDR x, GM_ADDR values, GM_ADDR indices,
                                                        GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k03176Custom op;
    op.Init(x, values, indices,
            tiling_data.totalLength, tiling_data.columns, tiling_data.rowSize,
            tiling_data.tileLength, tiling_data.dim);
    op.Process();
}
